var createTutorProfile = async (userId, payload) => {
  const existing = await prisma.tutorProfile.findUnique({
    where: { userId }
  });
  if (existing) {
    throw new Error("Tutor profile already exists");
  }
  const result = await prisma.tutorProfile.create({
    data: {
      userId,
      ...payload
    }
  });
  return result;
};
var getAllTutors = async () => {
  return prisma.tutorProfile.findMany({
    include: {
      user: true
    }
  });
};
var getSingleTutor = async (id) => {
  return prisma.tutorProfile.findUnique({
    where: { id },
    include: {
      user: true
    }
  });
};
var updateTutorProfile = async (userId, payload) => {
  return prisma.tutorProfile.update({
    where: { userId },
    data: payload
  });
};
var updateAvailability = async (userId, availability) => {
  return prisma.tutorProfile.update({
    where: { userId },
    data: { availability }
  });
};
var TutorProfileService = {
  createTutorProfile,
  getAllTutors,
  getSingleTutor,
  updateTutorProfile,
  updateAvailability
};

