// src/middlewares/errorHandler.ts
var errorHandler = (err, req, res, next) => {
  let statusCode = 500;
  let message = "Internal Server Error";
  let details = null;
  if (err instanceof prismaNamespace_exports.PrismaClientValidationError) {
    statusCode = 400;
    message = "Invalid input data or missing required fields.";
  } else if (err instanceof prismaNamespace_exports.PrismaClientKnownRequestError) {
    switch (err.code) {
      case "P2002":
        statusCode = 400;
        message = "Duplicate value found. This record already exists.";
        details = err.meta?.target;
        break;
      case "P2025":
        statusCode = 404;
        message = "Requested resource not found.";
        break;
      case "P2003":
        statusCode = 400;
        message = "Foreign key constraint failed.";
        break;
      case "P2014":
        statusCode = 400;
        message = "Invalid relation data.";
        break;
      case "P2016":
        statusCode = 400;
        message = "Query interpretation error.";
        break;
      default:
        statusCode = 400;
        message = "Database request error.";
    }
  } else if (err instanceof prismaNamespace_exports.PrismaClientUnknownRequestError) {
    statusCode = 500;
    message = "Unknown database error occurred.";
  } else if (err instanceof prismaNamespace_exports.PrismaClientInitializationError) {
    statusCode = 500;
    message = "Database connection failed.";
  } else if (err instanceof prismaNamespace_exports.PrismaClientRustPanicError) {
    statusCode = 500;
    message = "Critical database error.";
  } else if (err.name === "ZodError") {
    statusCode = 400;
    message = "Validation failed.";
    details = err.errors;
  } else if (err.message?.includes("Unauthorized")) {
    statusCode = 401;
    message = "Unauthorized access.";
  } else {
    message = err.message || message;
  }
  res.status(statusCode).json({
    success: false,
    message,
    error: process.env.NODE_ENV === "development" ? err : void 0,
    details
  });
};
var errorHandler_default = errorHandler;

